from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass
from enum import StrEnum
from pathlib import Path
from typing import Literal


class NavigationTarget(StrEnum):
    HOME = "home"
    CHANGES = "changes"
    HISTORY = "history"
    BRANCHES = "branches"
    FILES = "files"


VIEW_ORDER: tuple[NavigationTarget, ...] = (
    NavigationTarget.HOME,
    NavigationTarget.CHANGES,
    NavigationTarget.HISTORY,
    NavigationTarget.BRANCHES,
    NavigationTarget.FILES,
)


class DetailSlotId(StrEnum):
    SELECTION = "selection"
    METADATA = "metadata"
    GUIDANCE = "guidance"


@dataclass(frozen=True, slots=True)
class OperationSummary:
    kind: Literal["merge", "rebase"]
    summary: str
    conflicts: tuple[str, ...] = ()


@dataclass(frozen=True, slots=True)
class RepositoryDescriptor:
    name: str
    root: Path | None = None
    current_branch: str | None = None
    head_commit: str | None = None
    status_text: str = ""
    is_lit_repository: bool = False
    operation: OperationSummary | None = None
    attention: str = ""


@dataclass(frozen=True, slots=True)
class RecentRepository:
    name: str
    root: Path
    summary: str = ""
    is_lit_repository: bool = False


@dataclass(frozen=True, slots=True)
class SummaryItem:
    label: str
    value: str


@dataclass(frozen=True, slots=True)
class DetailSlotState:
    slot_id: DetailSlotId
    title: str
    body: str


@dataclass(frozen=True, slots=True)
class DetailPaneState:
    selection: DetailSlotState
    metadata: DetailSlotState
    guidance: DetailSlotState

    @classmethod
    def placeholder(
        cls,
        *,
        selection_title: str,
        selection_body: str,
        metadata_title: str,
        metadata_body: str,
        guidance_title: str,
        guidance_body: str,
    ) -> "DetailPaneState":
        return cls(
            selection=DetailSlotState(
                slot_id=DetailSlotId.SELECTION,
                title=selection_title,
                body=selection_body,
            ),
            metadata=DetailSlotState(
                slot_id=DetailSlotId.METADATA,
                title=metadata_title,
                body=metadata_body,
            ),
            guidance=DetailSlotState(
                slot_id=DetailSlotId.GUIDANCE,
                title=guidance_title,
                body=guidance_body,
            ),
        )

    def slots(self) -> tuple[DetailSlotState, ...]:
        return (self.selection, self.metadata, self.guidance)


@dataclass(frozen=True, slots=True)
class BaseViewState:
    route: NavigationTarget
    title: str
    subtitle: str
    detail: DetailPaneState


@dataclass(frozen=True, slots=True)
class ChangedPath:
    path: str
    change_kind: Literal["added", "modified", "deleted", "untracked"]
    staged: bool = False
    note: str = ""


@dataclass(frozen=True, slots=True)
class CommitSummary:
    commit_id: str
    message: str
    author: str = ""
    committed_at: str = ""
    changed_paths: tuple[str, ...] = ()


@dataclass(frozen=True, slots=True)
class BranchSummary:
    name: str
    commit_id: str | None = None
    is_current: bool = False
    note: str = ""


@dataclass(frozen=True, slots=True)
class FileNode:
    path: str
    display_name: str
    node_kind: Literal["directory", "file"]
    depth: int = 0


@dataclass(frozen=True, slots=True)
class HomeViewState(BaseViewState):
    context: RepositoryDescriptor | None = None
    highlights: tuple[SummaryItem, ...] = ()
    recent_repositories: tuple[RecentRepository, ...] = ()
    call_to_action: str = ""


@dataclass(frozen=True, slots=True)
class ChangesViewState(BaseViewState):
    context: RepositoryDescriptor | None = None
    highlights: tuple[SummaryItem, ...] = ()
    staged: tuple[ChangedPath, ...] = ()
    unstaged: tuple[ChangedPath, ...] = ()
    selected_path: str | None = None
    can_commit: bool = False
    commit_message_hint: str = ""


@dataclass(frozen=True, slots=True)
class HistoryViewState(BaseViewState):
    context: RepositoryDescriptor | None = None
    highlights: tuple[SummaryItem, ...] = ()
    commits: tuple[CommitSummary, ...] = ()
    selected_commit: str | None = None
    selected_path: str | None = None


@dataclass(frozen=True, slots=True)
class BranchesViewState(BaseViewState):
    context: RepositoryDescriptor | None = None
    highlights: tuple[SummaryItem, ...] = ()
    branches: tuple[BranchSummary, ...] = ()
    selected_branch: str | None = None
    can_checkout: bool = False
    can_merge: bool = False
    can_rebase: bool = False
    restore_suggestion: str | None = None


@dataclass(frozen=True, slots=True)
class FilesViewState(BaseViewState):
    context: RepositoryDescriptor | None = None
    highlights: tuple[SummaryItem, ...] = ()
    tree: tuple[FileNode, ...] = ()
    selected_path: str | None = None


ShellViewState = HomeViewState | ChangesViewState | HistoryViewState | BranchesViewState | FilesViewState


@dataclass(frozen=True, slots=True)
class SessionSnapshot:
    repository: RepositoryDescriptor | None
    home: HomeViewState
    changes: ChangesViewState
    history: HistoryViewState
    branches: BranchesViewState
    files: FilesViewState

    @property
    def default_view(self) -> NavigationTarget:
        if self.repository is not None and self.repository.is_lit_repository:
            return NavigationTarget.CHANGES
        return NavigationTarget.HOME

    def for_view(self, target: NavigationTarget) -> ShellViewState:
        return {
            NavigationTarget.HOME: self.home,
            NavigationTarget.CHANGES: self.changes,
            NavigationTarget.HISTORY: self.history,
            NavigationTarget.BRANCHES: self.branches,
            NavigationTarget.FILES: self.files,
        }[target]


class RepositorySession(ABC):
    """Desktop GUI boundary: `lit_gui` is a PySide6 client over the existing Python `lit` backend. `RepositorySession` is the only query and mutation gateway and returns immutable DTOs for all views. The shell owns three stable regions (sidebar, active center view, right detail panel); feature views may fill slots but must not rewire the shell. Views do not import `lit.repository` directly and do not persist metadata inside user repositories."""

    @abstractmethod
    def snapshot(self) -> SessionSnapshot:
        """Return the latest immutable snapshot for all shell views."""

    @abstractmethod
    def open_repository(self, root: Path) -> SessionSnapshot:
        """Open an existing folder and rebuild every view state."""

    @abstractmethod
    def initialize_repository(self, root: Path) -> SessionSnapshot:
        """Initialize a repository and rebuild every view state."""

    @abstractmethod
    def refresh(self) -> SessionSnapshot:
        """Reload the active repository into a fresh snapshot."""

    @abstractmethod
    def stage_paths(self, paths: tuple[str, ...]) -> SessionSnapshot:
        """Stage the provided paths for commit."""

    @abstractmethod
    def restore_paths(self, paths: tuple[str, ...], *, source: str | None = None) -> SessionSnapshot:
        """Restore paths from the working tree or a specific revision."""

    @abstractmethod
    def commit(self, message: str) -> SessionSnapshot:
        """Create a commit and return the updated shell snapshot."""

    @abstractmethod
    def select_change(self, path: str) -> SessionSnapshot:
        """Update the selected change and its shared detail slots."""

    @abstractmethod
    def select_commit(self, commit_id: str) -> SessionSnapshot:
        """Update the selected history item and its shared detail slots."""

    @abstractmethod
    def select_commit_path(self, path: str | None) -> SessionSnapshot:
        """Update the selected changed file for the current history item."""

    @abstractmethod
    def create_branch(self, name: str, *, start_point: str | None = "HEAD") -> SessionSnapshot:
        """Create a branch and return the updated shell snapshot."""

    @abstractmethod
    def select_branch(self, branch_name: str) -> SessionSnapshot:
        """Update the selected branch and its shared detail slots."""

    @abstractmethod
    def checkout(self, revision: str) -> SessionSnapshot:
        """Switch to another branch or detach at a commit."""

    @abstractmethod
    def merge(self, revision: str) -> SessionSnapshot:
        """Start or complete a merge and return the updated shell snapshot."""

    @abstractmethod
    def abort_merge(self) -> SessionSnapshot:
        """Abort the active merge state and return the updated shell snapshot."""

    @abstractmethod
    def rebase(self, revision: str) -> SessionSnapshot:
        """Start or complete a rebase and return the updated shell snapshot."""

    @abstractmethod
    def abort_rebase(self) -> SessionSnapshot:
        """Abort the active rebase state and return the updated shell snapshot."""

    @abstractmethod
    def select_file(self, path: str) -> SessionSnapshot:
        """Update the selected file or tree node and its shared detail slots."""

from __future__ import annotations

from dataclasses import replace
from pathlib import Path
from typing import Callable, TypeVar

from lit.merge_ops import MergeResult, merge_revision
from lit.rebase_ops import RebaseResult, rebase_onto
from lit.repository import CheckoutRecord, Repository
from lit_gui.backend import SnapshotFeedback, SnapshotSelections, build_snapshot
from lit_gui.contracts import RepositorySession, SessionSnapshot
from lit_gui.persistence import RecentRepositoriesStore

_T = TypeVar("_T")


class LitRepositorySession(RepositorySession):
    def __init__(
        self,
        root: Path | None = None,
        *,
        recent_store: RecentRepositoriesStore | None = None,
    ) -> None:
        self._recent_store = recent_store or RecentRepositoriesStore()
        self._root = self._resolve_root(root or Path.cwd())
        self._repository: Repository | None = self._reload_repository(self._root)
        self._recent_roots: tuple[Path, ...] = self._recent_store.load()
        self._selections = SnapshotSelections()
        self._feedback: SnapshotFeedback | None = None
        self._snapshot = self._rebuild_snapshot()

    def snapshot(self) -> SessionSnapshot:
        return self._snapshot

    def open_repository(self, root: Path) -> SessionSnapshot:
        self._root = self._resolve_root(root)
        validation_error = self._validate_open_root(self._root)
        if validation_error is not None:
            self._repository = None
            self._selections = SnapshotSelections()
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(level="error", message=validation_error)
            )

        self._repository = self._reload_repository(self._root)
        self._selections = SnapshotSelections()
        self._remember_recent(self._root, persist=True)
        if self._repository is None:
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(
                    level="info",
                    message=f"No .lit metadata detected at {self._root}.",
                )
            )
        return self._rebuild_snapshot(
            feedback=SnapshotFeedback(
                level="success",
                message=f"Opened lit repository at {self._root}.",
            )
        )

    def initialize_repository(self, root: Path) -> SessionSnapshot:
        self._root = self._resolve_root(root)
        validation_error = self._validate_initialize_root(self._root)
        if validation_error is not None:
            self._repository = None
            self._selections = SnapshotSelections()
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(level="error", message=validation_error)
            )

        already_initialized = (self._root / ".lit").is_dir()
        self._repository = Repository.create(self._root)
        self._selections = SnapshotSelections()
        self._remember_recent(self._root, persist=True)
        message = (
            f"Opened existing lit repository at {self._root}."
            if already_initialized
            else f"Initialized empty lit repository in {self._repository.layout.dot_lit}."
        )
        return self._rebuild_snapshot(feedback=SnapshotFeedback(level="success", message=message))

    def refresh(self) -> SessionSnapshot:
        self._repository = self._reload_repository(self._root)
        message = (
            f"Repository refreshed at {self._root}."
            if self._repository is not None
            else f"No .lit metadata detected at {self._root}."
        )
        level = "success" if self._repository is not None else "info"
        return self._rebuild_snapshot(feedback=SnapshotFeedback(level=level, message=message))

    def stage_paths(self, paths: tuple[str, ...]) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: repository.stage(paths),
            on_success=lambda staged: SnapshotFeedback(
                level="success",
                message=f"staged {len(staged)} path(s)",
            ),
        )

    def restore_paths(self, paths: tuple[str, ...], *, source: str | None = None) -> SessionSnapshot:
        source_label = source or "HEAD"
        return self._run_repository_action(
            lambda repository: repository.restore(paths, source=source),
            on_success=lambda restored: SnapshotFeedback(
                level="success",
                message=f"restored {len(restored)} path(s) from {source_label}",
            ),
        )

    def commit(self, message: str) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: repository.commit(message),
            on_success=lambda commit_id: self._commit_feedback(commit_id, message),
            update_selections=lambda commit_id: replace(self._selections, commit_id=commit_id),
        )

    def select_change(self, path: str) -> SessionSnapshot:
        self._selections = replace(self._selections, change_path=path)
        return self._rebuild_snapshot()

    def select_commit(self, commit_id: str) -> SessionSnapshot:
        self._selections = replace(self._selections, commit_id=commit_id, commit_path=None)
        return self._rebuild_snapshot()

    def select_commit_path(self, path: str | None) -> SessionSnapshot:
        self._selections = replace(self._selections, commit_path=path)
        return self._rebuild_snapshot()

    def create_branch(self, name: str, *, start_point: str | None = "HEAD") -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: repository.create_branch(name, start_point=start_point),
            on_success=lambda branch: SnapshotFeedback(
                level="success",
                message=f"{branch.name} -> {branch.commit_id[:12] if branch.commit_id else 'unborn'}",
            ),
            update_selections=lambda branch: replace(self._selections, branch_name=branch.name),
        )

    def select_branch(self, branch_name: str) -> SessionSnapshot:
        self._selections = replace(self._selections, branch_name=branch_name)
        return self._rebuild_snapshot()

    def checkout(self, revision: str) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: repository.checkout(revision),
            on_success=self._checkout_feedback,
            update_selections=self._checkout_selections,
        )

    def merge(self, revision: str) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: merge_revision(repository, revision),
            on_success=self._merge_feedback,
            update_selections=self._merge_selections,
        )

    def abort_merge(self) -> SessionSnapshot:
        def abort(repository: Repository) -> str:
            state = repository.read_merge_state()
            if state is None:
                raise ValueError("No merge in progress.")
            repository.apply_commit(
                state.current_commit,
                baseline_commit=repository.current_commit_id(),
            )
            repository.clear_merge()
            return state.current_commit

        return self._run_repository_action(
            abort,
            on_success=lambda _: SnapshotFeedback(level="success", message="Merge state cleared."),
            update_selections=lambda commit_id: replace(
                self._selections,
                change_path=None,
                commit_id=commit_id,
            ),
        )

    def rebase(self, revision: str) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: rebase_onto(repository, revision),
            on_success=self._rebase_feedback,
            update_selections=self._rebase_selections,
        )

    def abort_rebase(self) -> SessionSnapshot:
        def abort(repository: Repository) -> str:
            state = repository.read_rebase_state()
            if state is None:
                raise ValueError("No rebase in progress.")
            branch_name = repository.current_branch_name()
            if branch_name is not None:
                repository.write_branch(branch_name, state.original_head)
            repository.apply_commit(
                state.original_head,
                baseline_commit=repository.current_commit_id(),
            )
            repository.clear_rebase()
            return state.original_head

        return self._run_repository_action(
            abort,
            on_success=lambda _: SnapshotFeedback(level="success", message="Rebase state cleared."),
            update_selections=lambda commit_id: replace(
                self._selections,
                change_path=None,
                commit_id=commit_id,
            ),
        )

    def select_file(self, path: str) -> SessionSnapshot:
        self._selections = replace(self._selections, file_path=path)
        return self._rebuild_snapshot()

    def _run_repository_action(
        self,
        operation: Callable[[Repository], _T],
        *,
        on_success: Callable[[_T], SnapshotFeedback],
        update_selections: Callable[[_T], SnapshotSelections] | None = None,
    ) -> SessionSnapshot:
        repository = self._repository
        if repository is None:
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(
                    level="error",
                    message="Open or initialize a repository first.",
                )
            )

        try:
            result = operation(repository)
        except (FileNotFoundError, RuntimeError, ValueError) as error:
            self._repository = self._reload_repository(self._root)
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(level="error", message=str(error))
            )

        if update_selections is not None:
            self._selections = update_selections(result)
        self._repository = self._reload_repository(self._root)
        return self._rebuild_snapshot(feedback=on_success(result))

    def _rebuild_snapshot(self, *, feedback: SnapshotFeedback | None = None) -> SessionSnapshot:
        if feedback is not None:
            self._feedback = feedback
        self._snapshot, self._selections = build_snapshot(
            root=self._root,
            repository=self._repository,
            recent_roots=self._recent_roots,
            selections=self._selections,
            feedback=self._feedback,
        )
        return self._snapshot

    def _remember_recent(self, root: Path, *, persist: bool = False) -> None:
        ordered = [root]
        ordered.extend(existing for existing in self._recent_roots if existing != root)
        self._recent_roots = tuple(ordered[:5])
        if persist:
            self._recent_store.save(self._recent_roots)

    def _reload_repository(self, root: Path) -> Repository | None:
        try:
            return Repository.open(root)
        except FileNotFoundError:
            return None

    def _resolve_root(self, root: Path) -> Path:
        return Path(root).expanduser().resolve()

    def _validate_open_root(self, root: Path) -> str | None:
        if not root.exists():
            return f"Folder not found: {root}."
        if not root.is_dir():
            return f"Path is not a folder: {root}."
        return None

    def _validate_initialize_root(self, root: Path) -> str | None:
        if root.exists() and not root.is_dir():
            return f"Path is not a folder: {root}."
        return None

    def _commit_feedback(self, commit_id: str, message: str) -> SnapshotFeedback:
        branch_name = self._repository.current_branch_name() if self._repository is not None else None
        label = branch_name or "detached"
        return SnapshotFeedback(
            level="success",
            message=f"[{label} {commit_id[:12]}] {message}",
        )

    def _checkout_feedback(self, result: CheckoutRecord) -> SnapshotFeedback:
        if result.branch_name is not None:
            return SnapshotFeedback(
                level="success",
                message=f"switched to branch {result.branch_name}",
            )
        target = "unborn" if result.commit_id is None else result.commit_id[:12]
        return SnapshotFeedback(level="success", message=f"detached HEAD at {target}")

    def _checkout_selections(self, result: CheckoutRecord) -> SnapshotSelections:
        return replace(
            self._selections,
            branch_name=result.branch_name,
            commit_id=result.commit_id,
            change_path=None,
        )

    def _merge_selections(self, result: MergeResult) -> SnapshotSelections:
        branch_name = self._repository.current_branch_name() if self._repository is not None else self._selections.branch_name
        return replace(
            self._selections,
            branch_name=branch_name,
            change_path=result.conflicts[0] if result.conflicts else None,
            file_path=result.conflicts[0] if result.conflicts else self._selections.file_path,
            commit_id=result.commit_id if result.commit_id is not None else self._selections.commit_id,
        )

    def _rebase_selections(self, result: RebaseResult) -> SnapshotSelections:
        branch_name = self._repository.current_branch_name() if self._repository is not None else self._selections.branch_name
        return replace(
            self._selections,
            branch_name=branch_name,
            change_path=result.conflicts[0] if result.conflicts else None,
            file_path=result.conflicts[0] if result.conflicts else self._selections.file_path,
            commit_id=result.commit_id if result.commit_id is not None else self._selections.commit_id,
        )

    def _merge_feedback(self, result: MergeResult) -> SnapshotFeedback:
        level = "info" if result.status in {"conflict", "noop"} else "success"
        return SnapshotFeedback(level=level, message=result.message)

    def _rebase_feedback(self, result: RebaseResult) -> SnapshotFeedback:
        level = "info" if result.status in {"conflict", "noop"} else "success"
        return SnapshotFeedback(level=level, message=result.message)

from __future__ import annotations

import subprocess
from collections.abc import Mapping, Sequence
from dataclasses import dataclass
from pathlib import Path
from typing import Protocol

from lit.domain import (
    ArtifactRecord,
    CheckpointRecord,
    RevisionRecord,
    VerificationRecord,
    VerificationStatus,
)
from lit.layout import LitLayout
from lit.storage import hash_bytes, read_json, write_bytes, write_json
from lit.transactions import next_identifier, utc_now


@dataclass(frozen=True, slots=True)
class VerificationDefinition:
    name: str
    command: tuple[str, ...]
    command_identity: str | None = None

    @property
    def identity(self) -> str | None:
        if self.command_identity:
            return self.command_identity
        if not self.command:
            return None
        return " ".join(self.command)


@dataclass(frozen=True, slots=True)
class VerificationExecution:
    return_code: int
    stdout: bytes = b""
    stderr: bytes = b""
    started_at: str | None = None
    finished_at: str | None = None
    summary: str | None = None


@dataclass(frozen=True, slots=True)
class VerificationStatusSummary:
    owner_kind: str
    owner_id: str | None = None
    verification_id: str | None = None
    status: VerificationStatus = VerificationStatus.NEVER_VERIFIED
    summary: str | None = None
    command_identity: str | None = None
    state_fingerprint: str | None = None
    environment_fingerprint: str | None = None
    started_at: str | None = None
    finished_at: str | None = None
    return_code: int | None = None
    output_artifact_ids: tuple[str, ...] = ()


class VerificationExecutor(Protocol):
    def execute(
        self,
        definition: VerificationDefinition,
        *,
        cwd: Path,
    ) -> VerificationExecution: ...


class VerificationDefinitionService:
    def __init__(self, layout: LitLayout) -> None:
        self.layout = layout

    def list_definitions(self) -> tuple[VerificationDefinition, ...]:
        raw = self._load_raw_definitions()
        if raw is None:
            return ()
        if isinstance(raw, Mapping):
            return tuple(
                self._definition_from_mapping(
                    {"name": str(name), **candidate}
                    if isinstance(candidate, Mapping)
                    else {"name": str(name), "command": candidate}
                )
                for name, candidate in raw.items()
            )
        if isinstance(raw, Sequence) and not isinstance(raw, (str, bytes, bytearray)):
            return tuple(
                self._definition_from_candidate(candidate, index)
                for index, candidate in enumerate(raw, start=1)
            )
        raise ValueError("verification_commands must be a sequence or mapping")

    def get_definition(self, name: str | None = None) -> VerificationDefinition:
        definitions = self.list_definitions()
        if name is not None:
            for definition in definitions:
                if definition.name == name:
                    return definition
            raise KeyError(f"verification command not found: {name}")
        if len(definitions) == 1:
            return definitions[0]
        if not definitions:
            raise KeyError("repository does not define any verification commands")
        raise ValueError(
            "verification command name is required when multiple commands are configured"
        )

    def _load_raw_definitions(self) -> object | None:
        config = read_json(self.layout.config, default={}) or {}
        raw = config.get("verification_commands")
        if raw is not None:
            return raw
        verification = config.get("verification")
        if isinstance(verification, Mapping):
            return verification.get("commands")
        return None

    def _definition_from_candidate(
        self,
        candidate: object,
        index: int,
    ) -> VerificationDefinition:
        if isinstance(candidate, Mapping):
            return self._definition_from_mapping(
                candidate,
                fallback_name=f"verification-{index}",
            )
        return VerificationDefinition(
            name=f"verification-{index}",
            command=_command_tuple(candidate),
        )

    def _definition_from_mapping(
        self,
        candidate: Mapping[str, object],
        *,
        fallback_name: str | None = None,
    ) -> VerificationDefinition:
        name = str(candidate.get("name") or fallback_name or "verification")
        command = _command_tuple(candidate.get("command"))
        if not command:
            raise ValueError(f"verification command {name!r} requires a command")
        identity = _optional_string(candidate.get("command_identity"))
        return VerificationDefinition(
            name=name,
            command=command,
            command_identity=identity,
        )


class SubprocessVerificationExecutor:
    def execute(
        self,
        definition: VerificationDefinition,
        *,
        cwd: Path,
    ) -> VerificationExecution:
        if not definition.command:
            raise ValueError("verification command is required")
        started_at = utc_now()
        completed = subprocess.run(
            definition.command,
            cwd=str(cwd),
            capture_output=True,
            check=False,
        )
        finished_at = utc_now()
        return VerificationExecution(
            return_code=completed.returncode,
            stdout=completed.stdout,
            stderr=completed.stderr,
            started_at=started_at,
            finished_at=finished_at,
        )


class VerificationRecordStore:
    def __init__(self, layout: LitLayout) -> None:
        self.layout = layout

    def list_records(
        self,
        *,
        owner_kind: str | None = None,
        owner_id: str | None = None,
    ) -> tuple[VerificationRecord, ...]:
        records: list[VerificationRecord] = []
        for path in sorted(self.layout.verifications.glob("*.json")):
            record = VerificationRecord.from_dict(read_json(path, default=None))
            if owner_kind is not None and record.owner_kind != owner_kind:
                continue
            if owner_id is not None and record.owner_id != owner_id:
                continue
            records.append(record)
        records.sort(key=_record_sort_key)
        return tuple(records)

    def get_record(self, verification_id: str) -> VerificationRecord:
        path = self.layout.verification_path(verification_id)
        if not path.exists():
            raise FileNotFoundError(f"verification not found: {verification_id}")
        return VerificationRecord.from_dict(read_json(path, default=None))

    def find_cache_record(
        self,
        *,
        state_fingerprint: str | None,
        environment_fingerprint: str | None,
        command_identity: str | None,
    ) -> VerificationRecord | None:
        if not _has_complete_cache_key(
            state_fingerprint=state_fingerprint,
            environment_fingerprint=environment_fingerprint,
            command_identity=command_identity,
        ):
            return None
        candidates = [
            record
            for record in self.list_records()
            if record.state_fingerprint == state_fingerprint
            and record.environment_fingerprint == environment_fingerprint
            and record.command_identity == command_identity
            and replay_status_for(record.status) is not None
        ]
        if not candidates:
            return None
        return candidates[-1]

    def latest_owner_record(
        self,
        owner_kind: str,
        owner_id: str | None,
        *,
        command_identity: str | None = None,
    ) -> VerificationRecord | None:
        records = [
            record
            for record in self.list_records(owner_kind=owner_kind, owner_id=owner_id)
            if command_identity is None or record.command_identity == command_identity
        ]
        if not records:
            return None
        return records[-1]

    def persist_result(
        self,
        *,
        owner_kind: str,
        owner_id: str | None,
        status: VerificationStatus,
        summary: str | None,
        state_fingerprint: str | None,
        environment_fingerprint: str | None,
        command_identity: str | None,
        return_code: int | None,
        output_streams: Mapping[str, bytes | bytearray | str] | None = None,
        started_at: str | None = None,
        finished_at: str | None = None,
    ) -> VerificationRecord:
        verification_id = next_identifier("verification")
        artifact_ids = self._persist_output_artifacts(
            verification_id,
            output_streams or {},
        )
        record = VerificationRecord(
            verification_id=verification_id,
            owner_kind=owner_kind,
            owner_id=owner_id,
            status=status,
            summary=summary,
            state_fingerprint=state_fingerprint,
            environment_fingerprint=environment_fingerprint,
            command_identity=command_identity,
            started_at=started_at or utc_now(),
            finished_at=finished_at or utc_now(),
            return_code=return_code,
            output_artifact_ids=artifact_ids,
        )
        write_json(self.layout.verification_path(verification_id), record.to_dict())
        return record

    def get_artifact(self, artifact_id: str) -> ArtifactRecord:
        path = self.layout.artifact_record_path(artifact_id)
        if not path.exists():
            raise FileNotFoundError(f"artifact not found: {artifact_id}")
        return ArtifactRecord.from_dict(read_json(path, default=None))

    def _persist_output_artifacts(
        self,
        verification_id: str,
        output_streams: Mapping[str, bytes | bytearray | str],
    ) -> tuple[str, ...]:
        created_at = utc_now()
        artifact_ids: list[str] = []
        for name, payload in output_streams.items():
            data, content_type = _coerce_output_payload(payload)
            if not data:
                continue
            artifact_id = next_identifier("artifact")
            filename = _artifact_filename(name)
            payload_path = self.layout.artifact_payload_path(artifact_id, filename)
            write_bytes(payload_path, data)
            artifact = ArtifactRecord(
                artifact_id=artifact_id,
                owner_kind="verification",
                owner_id=verification_id,
                kind=f"verification-output/{name}",
                relative_path=payload_path.relative_to(self.layout.root).as_posix(),
                content_type=content_type,
                digest=hash_bytes(data),
                size_bytes=len(data),
                created_at=created_at,
            )
            write_json(self.layout.artifact_record_path(artifact_id), artifact.to_dict())
            artifact_ids.append(artifact_id)
        return tuple(artifact_ids)


class VerificationCacheService:
    def __init__(self, records: VerificationRecordStore) -> None:
        self.records = records

    def find_replayable_result(
        self,
        *,
        state_fingerprint: str | None,
        environment_fingerprint: str | None,
        command_identity: str | None,
    ) -> VerificationRecord | None:
        return self.records.find_cache_record(
            state_fingerprint=state_fingerprint,
            environment_fingerprint=environment_fingerprint,
            command_identity=command_identity,
        )

    def replay(self, record: VerificationRecord) -> VerificationRecord:
        replayed_status = replay_status_for(record.status)
        if replayed_status is None:
            raise ValueError(
                f"verification record {record.verification_id} is not replayable"
            )
        return VerificationRecord(
            verification_id=record.verification_id,
            owner_kind=record.owner_kind,
            owner_id=record.owner_id,
            status=replayed_status,
            summary=record.summary,
            state_fingerprint=record.state_fingerprint,
            environment_fingerprint=record.environment_fingerprint,
            command_identity=record.command_identity,
            started_at=record.started_at,
            finished_at=record.finished_at,
            return_code=record.return_code,
            output_artifact_ids=record.output_artifact_ids,
        )


class VerificationSummaryService:
    def __init__(
        self,
        records: VerificationRecordStore,
        cache: VerificationCacheService,
    ) -> None:
        self.records = records
        self.cache = cache

    def summarize_revision(
        self,
        revision: RevisionRecord,
        *,
        state_fingerprint: str | None = None,
        environment_fingerprint: str | None = None,
        command_identity: str | None = None,
    ) -> VerificationStatusSummary:
        return self.summarize_owner(
            owner_kind="revision",
            owner_id=revision.revision_id,
            linked_verification_id=revision.verification_id,
            state_fingerprint=state_fingerprint,
            environment_fingerprint=environment_fingerprint,
            command_identity=command_identity,
        )

    def summarize_checkpoint(
        self,
        checkpoint: CheckpointRecord,
        *,
        state_fingerprint: str | None = None,
        environment_fingerprint: str | None = None,
        command_identity: str | None = None,
    ) -> VerificationStatusSummary:
        return self.summarize_owner(
            owner_kind="checkpoint",
            owner_id=checkpoint.checkpoint_id,
            linked_verification_id=checkpoint.verification_id,
            state_fingerprint=state_fingerprint,
            environment_fingerprint=environment_fingerprint,
            command_identity=command_identity,
        )

    def summarize_owner(
        self,
        *,
        owner_kind: str,
        owner_id: str | None,
        linked_verification_id: str | None = None,
        state_fingerprint: str | None = None,
        environment_fingerprint: str | None = None,
        command_identity: str | None = None,
    ) -> VerificationStatusSummary:
        linked = self._resolve_linked_record(
            owner_kind=owner_kind,
            owner_id=owner_id,
            linked_verification_id=linked_verification_id,
            command_identity=command_identity,
        )
        exact = self.cache.find_replayable_result(
            state_fingerprint=state_fingerprint,
            environment_fingerprint=environment_fingerprint,
            command_identity=command_identity
            or (linked.command_identity if linked is not None else None),
        )
        if exact is not None:
            if linked is not None and exact.verification_id == linked.verification_id:
                return _summary_from_record(owner_kind, owner_id, exact, status=exact.status)
            return _summary_from_record(
                owner_kind,
                owner_id,
                exact,
                status=replay_status_for(exact.status) or exact.status,
            )
        if linked is not None:
            stale_reasons = _stale_reasons(
                linked,
                state_fingerprint=state_fingerprint,
                environment_fingerprint=environment_fingerprint,
            )
            if stale_reasons and replay_status_for(linked.status) is not None:
                return _summary_from_record(
                    owner_kind,
                    owner_id,
                    linked,
                    status=VerificationStatus.STALE,
                    summary=f"stale: {' and '.join(stale_reasons)}",
                )
            return _summary_from_record(owner_kind, owner_id, linked, status=linked.status)
        return VerificationStatusSummary(
            owner_kind=owner_kind,
            owner_id=owner_id,
            status=VerificationStatus.NEVER_VERIFIED,
            command_identity=command_identity,
            state_fingerprint=state_fingerprint,
            environment_fingerprint=environment_fingerprint,
        )

    def _resolve_linked_record(
        self,
        *,
        owner_kind: str,
        owner_id: str | None,
        linked_verification_id: str | None,
        command_identity: str | None,
    ) -> VerificationRecord | None:
        linked: VerificationRecord | None = None
        if linked_verification_id is not None:
            try:
                linked = self.records.get_record(linked_verification_id)
            except FileNotFoundError:
                linked = None
        if linked is None:
            linked = self.records.latest_owner_record(
                owner_kind,
                owner_id,
                command_identity=command_identity,
            )
        if linked is None:
            return None
        if command_identity is not None and linked.command_identity != command_identity:
            return self.records.latest_owner_record(
                owner_kind,
                owner_id,
                command_identity=command_identity,
            )
        return linked


class VerificationRunService:
    def __init__(
        self,
        layout: LitLayout,
        *,
        definitions: VerificationDefinitionService | None = None,
        records: VerificationRecordStore | None = None,
        cache: VerificationCacheService | None = None,
        executor: VerificationExecutor | None = None,
    ) -> None:
        self.layout = layout
        self.definitions = definitions or VerificationDefinitionService(layout)
        self.records = records or VerificationRecordStore(layout)
        self.cache = cache or VerificationCacheService(self.records)
        self.executor = executor or SubprocessVerificationExecutor()

    def verify(
        self,
        *,
        owner_kind: str,
        owner_id: str | None,
        definition_name: str | None = None,
        definition: VerificationDefinition | None = None,
        command: Sequence[str] = (),
        command_identity: str | None = None,
        state_fingerprint: str | None = None,
        environment_fingerprint: str | None = None,
        allow_cache: bool = True,
    ) -> VerificationRecord:
        resolved = self._resolve_definition(
            definition_name=definition_name,
            definition=definition,
            command=command,
            command_identity=command_identity,
        )
        identity = resolved.identity
        cached = None
        if allow_cache:
            cached = self.cache.find_replayable_result(
                state_fingerprint=state_fingerprint,
                environment_fingerprint=environment_fingerprint,
                command_identity=identity,
            )
        if cached is not None:
            return self.cache.replay(cached)

        execution = self.executor.execute(resolved, cwd=self.layout.root)
        status = (
            VerificationStatus.PASSED
            if execution.return_code == 0
            else VerificationStatus.FAILED
        )
        summary = execution.summary or _default_execution_summary(
            resolved,
            status=status,
            return_code=execution.return_code,
        )
        return self.records.persist_result(
            owner_kind=owner_kind,
            owner_id=owner_id,
            status=status,
            summary=summary,
            state_fingerprint=state_fingerprint,
            environment_fingerprint=environment_fingerprint,
            command_identity=identity,
            return_code=execution.return_code,
            output_streams={"stdout": execution.stdout, "stderr": execution.stderr},
            started_at=execution.started_at,
            finished_at=execution.finished_at,
        )

    def _resolve_definition(
        self,
        *,
        definition_name: str | None,
        definition: VerificationDefinition | None,
        command: Sequence[str],
        command_identity: str | None,
    ) -> VerificationDefinition:
        if definition is not None:
            base = definition
        elif command:
            base = VerificationDefinition(
                name=definition_name or "verification",
                command=_command_tuple(command),
                command_identity=command_identity,
            )
        else:
            base = self.definitions.get_definition(definition_name)
        if not base.command:
            raise ValueError("verification command is required")
        if command_identity is None or command_identity == base.identity:
            return base
        return VerificationDefinition(
            name=base.name,
            command=base.command,
            command_identity=command_identity,
        )


def replay_status_for(status: VerificationStatus) -> VerificationStatus | None:
    if status in {VerificationStatus.PASSED, VerificationStatus.CACHED_PASS}:
        return VerificationStatus.CACHED_PASS
    if status in {VerificationStatus.FAILED, VerificationStatus.CACHED_FAIL}:
        return VerificationStatus.CACHED_FAIL
    return None


def _command_tuple(command: object) -> tuple[str, ...]:
    if command is None:
        return ()
    if isinstance(command, (str, bytes, bytearray, Path)):
        return (str(command),)
    if isinstance(command, Sequence):
        return tuple(str(part) for part in command)
    return (str(command),)


def _optional_string(value: object | None) -> str | None:
    if value is None:
        return None
    text = str(value)
    return text or None


def _coerce_output_payload(payload: bytes | bytearray | str) -> tuple[bytes, str]:
    if isinstance(payload, bytearray):
        return bytes(payload), "application/octet-stream"
    if isinstance(payload, bytes):
        return payload, "application/octet-stream"
    return str(payload).encode("utf-8"), "text/plain; charset=utf-8"


def _artifact_filename(name: str) -> str:
    safe = "".join(
        character if character.isalnum() else "-"
        for character in name
    ).strip("-")
    return f"{safe or 'payload'}.txt"


def _has_complete_cache_key(
    *,
    state_fingerprint: str | None,
    environment_fingerprint: str | None,
    command_identity: str | None,
) -> bool:
    return all((state_fingerprint, environment_fingerprint, command_identity))


def _record_sort_key(record: VerificationRecord) -> tuple[str, str]:
    return (
        record.finished_at or record.started_at or "",
        record.verification_id or "",
    )


def _stale_reasons(
    record: VerificationRecord,
    *,
    state_fingerprint: str | None,
    environment_fingerprint: str | None,
) -> tuple[str, ...]:
    reasons: list[str] = []
    if state_fingerprint is not None and record.state_fingerprint != state_fingerprint:
        reasons.append("state fingerprint changed")
    if (
        environment_fingerprint is not None
        and record.environment_fingerprint != environment_fingerprint
    ):
        reasons.append("environment fingerprint changed")
    return tuple(reasons)


def _default_execution_summary(
    definition: VerificationDefinition,
    *,
    status: VerificationStatus,
    return_code: int,
) -> str:
    if status is VerificationStatus.PASSED:
        return f"{definition.name} passed"
    return f"{definition.name} failed with exit code {return_code}"


def _summary_from_record(
    owner_kind: str,
    owner_id: str | None,
    record: VerificationRecord,
    *,
    status: VerificationStatus,
    summary: str | None = None,
) -> VerificationStatusSummary:
    return VerificationStatusSummary(
        owner_kind=owner_kind,
        owner_id=owner_id,
        verification_id=record.verification_id,
        status=status,
        summary=record.summary if summary is None else summary,
        command_identity=record.command_identity,
        state_fingerprint=record.state_fingerprint,
        environment_fingerprint=record.environment_fingerprint,
        started_at=record.started_at,
        finished_at=record.finished_at,
        return_code=record.return_code,
        output_artifact_ids=record.output_artifact_ids,
    )


__all__ = [
    "SubprocessVerificationExecutor",
    "VerificationCacheService",
    "VerificationDefinition",
    "VerificationDefinitionService",
    "VerificationExecution",
    "VerificationExecutor",
    "VerificationRecordStore",
    "VerificationRunService",
    "VerificationStatusSummary",
    "VerificationSummaryService",
    "replay_status_for",
]

