def _build_recent_repositories(
    *,
    active_root: Path,
    repository: Repository | None,
    recent_roots: tuple[Path, ...],
) -> tuple[RecentRepository, ...]:
    ordered: list[Path] = []
    for candidate in (active_root, *recent_roots):
        resolved = candidate.resolve()
        if resolved not in ordered:
            ordered.append(resolved)

    entries: list[RecentRepository] = []
    for root in ordered[:5]:
        is_lit_repository = (root == active_root and repository is not None) or (root / ".lit").is_dir()
        summary = (
            _repository_status_text(repository, repository.status(), repository.current_operation())
            if root == active_root and repository is not None
            else _recent_repository_summary(root, is_lit_repository)
        )
        entries.append(
            RecentRepository(
                name=root.name or str(root),
                root=root,
                summary=summary,
                is_lit_repository=is_lit_repository,
            )
        )
    return tuple(entries)


def _build_change_lists(status: StatusReport) -> tuple[tuple[ChangedPath, ...], tuple[ChangedPath, ...]]:
    staged = tuple(
        ChangedPath(path=path, change_kind="added", staged=True)
        for path in status.staged_added
    ) + tuple(
        ChangedPath(path=path, change_kind="modified", staged=True)
        for path in status.staged_modified
    ) + tuple(
        ChangedPath(path=path, change_kind="deleted", staged=True)
        for path in status.staged_deleted
    )
    unstaged = tuple(
        ChangedPath(path=path, change_kind="modified")
        for path in status.modified
    ) + tuple(
        ChangedPath(path=path, change_kind="deleted")
        for path in status.deleted
    ) + tuple(
        ChangedPath(path=path, change_kind="untracked")
        for path in status.untracked
    )
    return staged, unstaged


def _build_commit_summaries(repository: Repository) -> tuple[CommitSummary, ...]:
    commits: list[CommitSummary] = []
    for commit_id, record in repository.iter_history():
        commits.append(
            CommitSummary(
                commit_id=commit_id,
                message=record.summary,
                author=record.metadata.author,
                committed_at=record.metadata.committed_at or "",
                changed_paths=_changed_paths_for_commit(repository, commit_id),
            )
        )
    return tuple(commits)


def _build_branch_summaries(repository: Repository) -> tuple[BranchSummary, ...]:
    return tuple(
        BranchSummary(
            name=branch.name,
            commit_id=branch.commit_id,
            is_current=branch.current,
            note=_branch_note(branch),
        )
        for branch in repository.list_branches()
    )


def _build_file_tree(root: Path) -> tuple[FileNode, ...]:
    nodes: list[FileNode] = []

    def visit(directory: Path, depth: int) -> None:
        entries = [
            entry
            for entry in sorted(
                directory.iterdir(),
                key=lambda item: (not item.is_dir(), item.name.lower(), item.name),
            )
            if entry.name != ".lit"
        ]
        for entry in entries:
            relative = normalize_repo_path(entry.relative_to(root))
            nodes.append(
                FileNode(
                    path=relative,
                    display_name=entry.name,
                    node_kind="directory" if entry.is_dir() else "file",
                    depth=depth,
                )
            )
            if entry.is_dir():
                visit(entry, depth + 1)

    if root.exists():
        visit(root, 0)
    return tuple(nodes)


def _ordered_unique_paths(entries: tuple[ChangedPath, ...]) -> tuple[str, ...]:
    seen: set[str] = set()
    ordered: list[str] = []
    for entry in entries:
        if entry.path in seen:
            continue
        seen.add(entry.path)
        ordered.append(entry.path)
    return tuple(ordered)


def _pick_selection(
    *,
    preferred: str | None,
    available: tuple[str, ...],
    fallback: str | None = None,
) -> str | None:
    allowed = set(available)
    if preferred in allowed:
        return preferred
    if fallback in allowed:
        return fallback
    return available[0] if available else None


def _first_file_path(tree: tuple[FileNode, ...]) -> str | None:
    for node in tree:
        if node.node_kind == "file":
            return node.path
    return None


def _changed_paths_for_commit(repository: Repository, commit_id: str) -> tuple[str, ...]:
    record = repository.read_commit(commit_id)
    current = repository.read_commit_tree(commit_id)
    parent = repository.read_commit_tree(record.primary_parent)
    changed = sorted(
        path
        for path in set(current) | set(parent)
        if not _tracked_file_equal(current.get(path), parent.get(path))
    )
    return tuple(changed)


def _tracked_file_equal(left: TrackedFile | None, right: TrackedFile | None) -> bool:
    if left is None or right is None:
        return left is None and right is None
    return (
        left.digest == right.digest
        and left.executable == right.executable
        and left.size == right.size
    )


def _guidance(*, base: str, feedback: SnapshotFeedback | None) -> tuple[str, str]:
    if feedback is None:
        return "Next action", base
    title = {
        "error": "Action blocked",
        "info": "Latest action",
        "success": "Latest action",
    }[feedback.level]
    return title, f"{feedback.message}\n\n{base}"


def _repository_status_text(
    repository: Repository,
    status: StatusReport,
    operation: OperationState | None,
) -> str:
    if operation is not None:
        operation_summary = _operation_summary(operation)
        return operation_summary.summary if operation_summary is not None else "Operation in progress."

    head_commit = repository.current_commit_id()
    if head_commit is None:
        if status.untracked:
            return f"Unborn branch with {len(status.untracked)} untracked path(s)."
        return "No commits yet."
    if status.is_clean():
        if repository.current_branch_name() is None:
            return f"Detached HEAD at {head_commit[:12]}."
        return "Working tree clean."

    parts: list[str] = []
    staged_count = len(status.staged_added) + len(status.staged_modified) + len(status.staged_deleted)
    unstaged_count = len(status.modified) + len(status.deleted)
    if staged_count:
        parts.append(f"{staged_count} staged")
    if unstaged_count:
        parts.append(f"{unstaged_count} unstaged")
    if status.untracked:
        parts.append(f"{len(status.untracked)} untracked")
    return ", ".join(parts) + " path(s)."


def _operation_summary(operation: OperationState | None) -> OperationSummary | None:
    if operation is None:
        return None

    if operation.kind == "merge":
        state = operation.state
        assert isinstance(state, MergeState)
        target = branch_name_from_ref(state.target_ref) or state.target_commit[:12]
        summary = (
            f"Merge in progress from {target} with {len(state.conflicts)} conflicting path(s)."
            if state.conflicts
            else f"Merge in progress from {target}."
        )
        return OperationSummary(kind="merge", summary=summary, conflicts=state.conflicts)

    state = operation.state
    assert isinstance(state, RebaseState)
    summary = (
        f"Rebase in progress onto {state.onto[:12]} with {len(state.conflicts)} conflicting path(s)."
        if state.conflicts
        else f"Rebase in progress onto {state.onto[:12]}."
    )
    return OperationSummary(kind="rebase", summary=summary, conflicts=state.conflicts)


def _repository_attention(
    *,
    status: StatusReport,
    operation_summary: OperationSummary | None,
) -> str:
    if operation_summary is not None:
        suffix = (
            f" Resolve the conflicted path(s): {', '.join(operation_summary.conflicts)}."
            if operation_summary.conflicts
            else ""
        )
        return (
            f"Manual resolution required. {operation_summary.summary}"
            f"{suffix} Abort {operation_summary.kind} is available."
        )
    if not _can_checkout(status, None):
        return "Checkout blocked until staged or tracked working tree changes are committed or restored."
    if status.untracked:
        return "Checkout is available, but untracked files can still block a specific target."
    return "Working tree ready for checkout, merge, and rebase."


def _can_commit(staged: tuple[ChangedPath, ...], operation: OperationState | None) -> bool:
    return bool(staged) and operation is None


def _commit_message_hint(staged: tuple[ChangedPath, ...], operation: OperationState | None) -> str:
    if operation is not None:
        return "Resolve or abort the active operation before creating another commit."
    if not staged:
        return "Stage one or more paths to enable commit."
    return "Enter a message to commit the staged paths."


def _changes_guidance(*, status: StatusReport, operation: OperationState | None) -> str:
    if operation is not None:
        return (
            "Resolve the listed conflicts or abort the active operation before staging, "
            "checking out, or committing more work."
        )
    if status.is_clean():
        return "Working tree clean. Edit files or switch branches to create new changes."
    return "Stage paths to prepare a commit, or restore them to discard working tree changes."


def _change_selection_body(repository: Repository, path: str | None) -> str:
    if path is None:
        return "No changed path selected."
    return _truncate_text(_render_change_preview(repository, path))


def _change_metadata(entries: tuple[ChangedPath, ...]) -> str:
    if not entries:

        return "No change metadata available."

    lines = [f"Path: {entries[0].path}"]
    states = [f"{'staged ' if entry.staged else ''}{entry.change_kind}" for entry in entries]
    lines.append(f"State: {', '.join(states)}")
    if len(entries) > 1:
        lines.append("This path has both staged and unstaged changes.")
    return "\n".join(lines)


def _render_change_preview(repository: Repository, path: str) -> str:
    head_file = repository.read_commit_tree(repository.current_commit_id()).get(path)
    before = [] if head_file is None else _decode_blob_lines(repository, head_file)
    working_path = repository.root / path
    after = [] if not working_path.exists() or not working_path.is_file() else _read_text_lines(working_path)
    diff_lines = list(
        unified_diff(
            before,
            after,
            fromfile=f"a/{path}",
            tofile=f"b/{path}",
            lineterm="",
        )
    )
    if diff_lines:
        return "\n".join(diff_lines)
    if working_path.exists() and working_path.is_file():
        return _read_preview_text(working_path)
    return "File was removed from the working tree."


def _commit_selection_body(
    repository: Repository,
    selected: CommitSummary | None,
    selected_path: str | None,
) -> str:
    if selected is None:
        return "No commit selected."
    if selected_path is None:
        return selected.message or "(empty commit message)"
    return _truncate_text(_render_commit_preview(repository, selected.commit_id, selected_path))


def _commit_metadata(
    repository: Repository,
    selected: CommitSummary | None,
    selected_path: str | None,
) -> str:
    if selected is None:
        return "No commit metadata available."

    record = repository.read_commit(selected.commit_id)
    parents = ", ".join(parent[:12] for parent in record.parents) or "none"
    committed_at = selected.committed_at or "unknown"
    lines = [
        f"Commit: {selected.commit_id}",
        f"Message: {selected.message or '(empty commit message)'}",
        f"Author: {selected.author or 'lit'}",
        f"Committed at: {committed_at}",
        f"Parents: {parents}",
        f"Changed paths: {', '.join(selected.changed_paths) or 'none'}",
    ]
    if selected_path is not None:
        lines.append(f"Selected path: {selected_path}")
    return "\n".join(lines)


def _render_commit_preview(repository: Repository, commit_id: str, path: str) -> str:
    record = repository.read_commit(commit_id)
    current = repository.read_commit_tree(commit_id).get(path)
    parent = repository.read_commit_tree(record.primary_parent).get(path)
    before = [] if parent is None else _decode_blob_lines(repository, parent)
    after = [] if current is None else _decode_blob_lines(repository, current)
    diff_lines = list(
        unified_diff(
            before,
            after,
            fromfile=f"a/{path}",
            tofile=f"b/{path}",
            lineterm="",
        )
    )
    if diff_lines:
        return "\n".join(diff_lines)
    if current is not None:
        return repository.read_object("blobs", current.digest).decode("utf-8", errors="replace")
    return "File was removed by this commit."


def _branch_guidance(
    *,
    repository: Repository,
    status: StatusReport,
    operation: OperationState | None,
    can_checkout: bool,
    can_merge: bool,
    can_rebase: bool,
) -> str:
    if operation is not None:
        conflicts = operation.state.conflicts
        if operation.kind == "merge":
            target = _merge_target_label(operation.state)
            if conflicts:
                return (
                    f"Manual resolution required for the merge from {target}. "
                    f"Conflicted paths: {', '.join(conflicts)}. Use Restore to discard a path from HEAD "
                    "or Abort Merge to return to the pre-merge tree."
                )
            return (
                f"Merge in progress from {target}. Finish the working tree cleanup or abort the merge "
                "before checking out another branch."
            )
        onto = _rebase_target_label(operation.state)
        if conflicts:
            return (
                f"Manual resolution required for the rebase onto {onto}. "
                f"Conflicted paths: {', '.join(conflicts)}. Use Restore to discard a path from HEAD "
                "or Abort Rebase to return to the original branch tip."
            )
        return (
            f"Rebase in progress onto {onto}. Finish the working tree cleanup or abort the rebase "
            "before checking out another branch."
        )
    if not can_checkout:
        return (
            "Checkout is blocked by staged or tracked working tree changes. Commit them or use Restore "
            "before switching branches or detaching HEAD."
        )
    if repository.current_branch_name() is None:
        return "HEAD is detached. Checkout a branch before starting a merge or rebase."
    if repository.current_commit_id() is None:
        return "Create the first commit before starting a merge or rebase."
    if status.untracked and not (can_merge and can_rebase):
        return (
            "Checkout is available, but untracked files can still block a specific target. "
            "Merge and rebase require a fully clean tree, including untracked paths."
        )
    return "Create a branch from HEAD, checkout another local branch or commit, restore a path, or start a merge or rebase."


def _can_checkout(status: StatusReport, operation: OperationState | None) -> bool:
    if operation is not None:
        return False
    return not any(
        (
            status.staged_added,
            status.staged_modified,
            status.staged_deleted,
            status.modified,
            status.deleted,
        )
    )


def _can_merge(
    repository: Repository,
    status: StatusReport,
    operation: OperationState | None,
) -> bool:
    if operation is not None or not status.is_clean():
        return False
    return repository.current_branch_name() is not None and repository.current_commit_id() is not None


def _can_rebase(
    repository: Repository,
    status: StatusReport,
    operation: OperationState | None,
) -> bool:
    if operation is not None or not status.is_clean():
        return False
    return repository.current_branch_name() is not None and repository.current_commit_id() is not None


def _branch_selection_title(operation: OperationState | None) -> str:
    if operation is None:
        return "Selected branch"
    if operation.state.conflicts:
        return "Manual resolution"
    return "Active operation"


def _branch_metadata_title(operation: OperationState | None) -> str:
    if operation is None:
        return "Branch metadata"
    return "Operation metadata"


def _branch_selection_body(
    *,
    selected: BranchSummary | None,
    descriptor: RepositoryDescriptor,
    operation: OperationState | None,
) -> str:
    if operation is not None:
        current_branch = descriptor.current_branch or "detached"
        if operation.kind == "merge":
            target = _merge_target_label(operation.state)
            lines = [f"{current_branch} has a merge in progress from {target}."]
        else:
            target = _rebase_target_label(operation.state)
            lines = [f"{current_branch} is rebasing onto {target}."]
            state = operation.state
            assert isinstance(state, RebaseState)
            if state.current_commit is not None:
                lines.append(f"Current replay commit: {state.current_commit[:12]}")
        if operation.state.conflicts:
            lines.append(f"Conflicted paths: {', '.join(operation.state.conflicts)}")
        else:
            lines.append("No conflicted paths are currently recorded.")
        return "\n".join(lines)
    if selected is None:
        return "No branch selected."
    target = selected.commit_id[:12] if selected.commit_id is not None else "unborn"
    prefix = "Current branch" if selected.is_current else "Local branch"
    return f"{prefix}: {selected.name} -> {target}"


def _branch_metadata(
    *,
    selected: BranchSummary | None,
    descriptor: RepositoryDescriptor,
    can_checkout: bool,
    can_merge: bool,
    can_rebase: bool,
) -> str:
    head_label = descriptor.head_commit or "unborn"
    lines = [
        f"Current branch: {descriptor.current_branch or 'detached'}",
        f"HEAD: {head_label}",
        f"Checkout: {'ready' if can_checkout else 'blocked'}",
        f"Merge: {'ready' if can_merge else 'blocked'}",
        f"Rebase: {'ready' if can_rebase else 'blocked'}",
    ]
    if descriptor.operation is not None:
        lines.append(f"Operation: {descriptor.operation.summary}")
        if descriptor.operation.conflicts:
            lines.append(f"Conflicts: {', '.join(descriptor.operation.conflicts)}")
    if selected is not None:
        target = selected.commit_id or "unborn"
        state = "current" if selected.is_current else "not current"
        note = selected.note or "No branch note."
        lines.extend(
            (
                f"Selected branch: {selected.name}",
                f"Selected target: {target}",
                f"Selected state: {state}",
                f"Selected note: {note}",
            )
        )
    return "\n".join(lines)


def _restore_suggestion(
    *,
    selected_change: str | None,
    operation: OperationState | None,
) -> str | None:
    if selected_change is not None:
        return selected_change
    if operation is not None and operation.state.conflicts:
        return operation.state.conflicts[0]
    return None


def _merge_target_label(state: MergeState) -> str:
    return branch_name_from_ref(state.target_ref) or state.target_commit[:12]


def _rebase_target_label(state: RebaseState) -> str:
    return state.onto[:12]


def _branch_note(branch: BranchRecord) -> str:
    if branch.current:
        return "Checked out."
    if branch.commit_id is None:
        return "Unborn branch."
    return f"Points to {branch.commit_id[:12]}."


def _file_selection_body(repository: Repository, selected: FileNode | None) -> str:
    if selected is None:
        return "No file selected."

    target = repository.root / selected.path
    if selected.node_kind == "directory":
        return _directory_preview(target)
    if not target.exists():
        return "File is no longer present in the working tree."
    return _truncate_text(_read_preview_text(target))


def _file_metadata(repository: Repository, status: StatusReport, selected: FileNode | None) -> str:
    if selected is None:
        return "No file metadata available."

    staged_paths = set(status.staged_added) | set(status.staged_modified) | set(status.staged_deleted)
    unstaged_paths = set(status.modified) | set(status.deleted)
    labels: list[str] = []
    if selected.path in staged_paths:
        labels.append("staged")
    if selected.path in unstaged_paths:
        labels.append("unstaged")
    if selected.path in set(status.untracked):
        labels.append("untracked")
    if not labels and selected.node_kind == "file":
        labels.append("tracked")

    target = repository.root / selected.path
    size = target.stat().st_size if target.exists() and target.is_file() else 0
    state = ", ".join(labels) if labels else "n/a"
    return f"Path: {selected.path}\nKind: {selected.node_kind}\nState: {state}\nSize: {size} bytes"


def _directory_preview(path: Path) -> str:
    if not path.exists():
        return "Directory is no longer present in the working tree."

    children = [
        child.name
        for child in sorted(
            path.iterdir(),
            key=lambda item: (not item.is_dir(), item.name.lower(), item.name),
        )
        if child.name != ".lit"
    ]
    if not children:
        return "Empty directory."

    listed = children[:_MAX_DIRECTORY_PREVIEW_ITEMS]
    preview = "\n".join(listed)
    if len(children) > len(listed):
        preview += f"\n... and {len(children) - len(listed)} more"
    return preview


def _read_preview_text(path: Path) -> str:
    payload = path.read_bytes()
    if b"\x00" in payload:
        return "Binary preview unavailable."
    text = payload.decode("utf-8", errors="replace")
    return text if text else "(empty file)"


def _decode_blob_lines(repository: Repository, tracked_file: TrackedFile) -> list[str]:
    payload = repository.read_object("blobs", tracked_file.digest)
    return payload.decode("utf-8", errors="replace").splitlines()


def _read_text_lines(path: Path) -> list[str]:
    return path.read_text(encoding="utf-8", errors="replace").splitlines()


def _truncate_text(text: str) -> str:
    if len(text) <= _MAX_PREVIEW_CHARS:
        return text
    return text[:_MAX_PREVIEW_CHARS].rstrip() + "\n...\n[truncated]"


def _folder_status(root: Path) -> str:
    if root.exists() and root.is_dir():
        return "No .lit metadata detected yet."
    if root.exists():
        return "Selected path is not a folder."
    return "Folder does not exist yet."


def _non_repository_subtitle(root: Path) -> str:
    if root.exists() and root.is_dir():
        return "Open an existing lit repository or initialize this folder in place."
    if root.exists():
        return "Choose a folder path to open or initialize a local-only repository."
    return "Open an existing lit repository or initialize this new folder in place."


def _non_repository_call_to_action(root: Path) -> str:
    if root.exists() and root.is_dir():
        return "Initialize this folder to start local-only history."
    if root.exists():
        return "Enter a folder path, then open or initialize it."
    return "Initialize this folder to create it and start local-only history."


def _non_repository_guidance(root: Path) -> str:
    if root.exists() and root.is_dir():
        return (
            "Initialize this folder to create a local-only repository, or open another folder "
            "that already contains .lit metadata."
        )
    if root.exists():
        return "The selected path is not a folder. Pick a directory before opening or initializing."
    return "This folder does not exist yet. Initialize it to create the directory and .lit metadata."


def _non_repository_metadata(root: Path) -> str:
    if root.exists() and root.is_dir():
        return "No .lit directory was found in this folder."
    if root.exists():
        return "The selected path points to a file, so repository actions are unavailable."
    return "The selected folder has not been created yet."


def _recent_repository_summary(root: Path, is_lit_repository: bool) -> str:
    if is_lit_repository:
        return "lit repository"
    if root.exists() and root.is_dir():
        return "Initialize this folder to start local history."
    if root.exists():
        return "Path is not a folder."
    return "Folder unavailable."
